{
  "to": "Cbb4c5f107bc25421664b3bc21cc37e15",
  "messages": [
    {
      "type": "flex",
      "altText": "新特約商店申請",
      "contents": {
        "type": "bubble",
        "hero": {
          "type": "image",
          "url": "{{28.hero_image_url}}",
          "size": "full",
          "aspectRatio": "20:13",
          "aspectMode": "cover"
        },
        "body": {
          "type": "box",
          "layout": "vertical",
          "spacing": "md",
          "paddingAll": "16px",
          "contents": [
            {
              "type": "text",
              "text": "特約商店申請",
              "weight": "bold",
              "size": "xl",
              "color": "#C49A3C"
            },
            {
              "type": "box",
              "layout": "horizontal",
              "margin": "sm",
              "contents": [
                {
                  "type": "box",
                  "layout": "vertical",
                  "cornerRadius": "12px",
                  "backgroundColor": "#fef3c7",
                  "paddingTop": "4px",
                  "paddingBottom": "4px",
                  "paddingStart": "12px",
                  "paddingEnd": "12px",
                  "flex": 0,
                  "contents": [
                    {
                      "type": "text",
                      "text": "{{trim(1.cate)}}",
                      "size": "xs",
                      "color": "#92400e",
                      "weight": "bold",
                      "align": "center"
                    }
                  ]
                },
                {
                  "type": "filler"
                }
              ]
            },
            {
              "type": "text",
              "text": "{{trim(1.title)}}",
              "weight": "bold",
              "size": "lg",
              "wrap": true,
              "color": "#111827",
              "margin": "md"
            },
            {
              "type": "separator",
              "margin": "lg"
            },
            {
              "type": "box",
              "layout": "baseline",
              "spacing": "sm",
              "margin": "lg",
              "contents": [
                {
                  "type": "text",
                  "text": "申請人",
                  "size": "sm",
                  "color": "#9ca3af",
                  "flex": 2
                },
                {
                  "type": "text",
                  "text": "{{trim(1.name)}}",
                  "size": "sm",
                  "color": "#374151",
                  "flex": 5
                }
              ]
            },
            {
              "type": "box",
              "layout": "baseline",
              "spacing": "sm",
              "contents": [
                {
                  "type": "text",
                  "text": "連絡電話",
                  "size": "sm",
                  "color": "#9ca3af",
                  "flex": 2
                },
                {
                  "type": "text",
                  "text": "{{ifempty(trim(1.phone); \"—\")}}",
                  "size": "sm",
                  "color": "#374151",
                  "flex": 5
                }
              ]
            },
            {
              "type": "box",
              "layout": "baseline",
              "spacing": "sm",
              "contents": [
                {
                  "type": "text",
                  "text": "特約方案",
                  "size": "sm",
                  "color": "#9ca3af",
                  "flex": 2
                },
                {
                  "type": "text",
                  "text": "{{trim(1.planType)}}",
                  "size": "sm",
                  "color": "#374151",
                  "flex": 5
                }
              ]
            }
          ]
        },
        "footer": {
          "type": "box",
          "layout": "vertical",
          "paddingAll": "12px",
          "contents": [
            {
              "type": "button",
              "style": "primary",
              "color": "#C49A3C",
              "height": "sm",
              "action": {
                "type": "uri",
                "label": "審核商店",
                "uri": "{{3.data.short_url}}"
              }
            }
          ]
        }
      }
    }
  ]
}
